INSERT INTO poems (
  poet_id, poem_no, volume, title_zh, title_ko, category, meter, body_zh,
  is_notable, status, quality, review_memo
)
SELECT
  p.id,
  COALESCE(existing_poem_count.max_poem_no, 0)
    + row_number() OVER (PARTITION BY p.id ORDER BY ip.title_zh, ip.body_zh)::integer,
  ip.volume::integer, ip.title_zh, ip.title_ko, ip.category, ip.meter::integer, ip.body_zh,
  TRUE, ip.status, ip.quality, ip.review_memo
FROM input_poems ip
JOIN poets p ON p.title_id = ip.poet_slug
LEFT JOIN LATERAL (
  SELECT max(poem_no) AS max_poem_no
  FROM poems
  WHERE poet_id = p.id
) existing_poem_count ON TRUE
WHERE NOT EXISTS (
  SELECT 1
  FROM poems existing
  WHERE existing.poet_id = p.id
    AND existing.title_zh = ip.title_zh
    AND existing.body_zh = ip.body_zh
);

UPDATE poets p
SET poem_count = sub.cnt
FROM (
  SELECT poet_id, count(*)::integer AS cnt
  FROM poems
  WHERE poet_id IN (SELECT id FROM poets WHERE title_id IN ('candidate-ming-5f90-71a5', 'candidate-ming-5f90-4e2d-884c', 'candidate-ming-6234-9be8', 'candidate-yuan-6234-9c32', 'candidate-ming-6234-4c80', 'candidate-song-5289-93ae', 'candidate-song-5433-60df-4fe1', 'candidate-song-5b8b-81ea-905c', 'candidate-song-9678-904a', 'candidate-song-6b50-967d-4fee', 'candidate-song-5468-6587-749e', 'candidate-song-84b2-58fd-5bac', 'candidate-yuan-5584-4f4f', 'candidate-ming-674e-5ef6-8208', 'candidate-ming-85cd-667a', 'candidate-ming-738b-7acb-9053', 'candidate-ming-912d-5b78-9187', 'candidate-ming-76db-9cf4-4e16', 'candidate-song-6641-6c96-4e4b', 'candidate-ming-9b4f-5141-4e2d', 'candidate-ming-80e1-594e', 'candidate-song-4ef2-4e26', 'candidate-song-5289-624d-90b5', 'candidate-song-5b8b-5ea0', 'candidate-song-674e-89af', 'candidate-song-8607-8f4d', 'candidate-song-9112-6d69', 'candidate-song-5f90-5ead-7b60', 'candidate-song-8881-71ee', 'candidate-song-8607-6cc2', 'candidate-ming-674e-5922-967d', 'candidate-ming-516c-9f10', 'candidate-ming-65b9-5b5f-5f0f', 'candidate-ming-6c5f-6e90'))
  GROUP BY poet_id
) sub
WHERE p.id = sub.poet_id;

